import{_ as i,o as a,c as e,a3 as t}from"./chunks/framework.q4B3G9ZH.js";const c=JSON.parse('{"title":"延迟渲染","description":"","frontmatter":{},"headers":[],"relativePath":"图形学/延迟渲染.md","filePath":"图形学/延迟渲染.md","lastUpdated":null}'),r={name:"图形学/延迟渲染.md"};function o(n,l,u,s,h,p){return a(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="延迟渲染" tabindex="-1">延迟渲染 <a class="header-anchor" href="#延迟渲染" aria-label="Permalink to &quot;延迟渲染&quot;">​</a></h1><p>延迟渲染的实质：</p><ul><li>先不做迭代三角形做光照计算，而是先找出你能看到的所有像素，再去迭代光照。就是先找出摄像机能看到的像素/顶点。</li><li>直接迭代三角形的话，由于大量三角形是看不到的，会造成极大的浪费。就是说一些被遮挡的物体，以及几何体的背面之类的。</li></ul><h2 id="延迟渲染vs前向渲染" tabindex="-1">延迟渲染VS前向渲染 <a class="header-anchor" href="#延迟渲染vs前向渲染" aria-label="Permalink to &quot;延迟渲染VS前向渲染&quot;">​</a></h2><p><strong>前向渲染</strong>：</p><ul><li>优点： <ul><li>支持半透明物体渲染</li><li>支持使用多个光照pass</li><li>支持每个物体单独计算光照，不同物体可以有不同的光照计算方式</li></ul></li><li>缺点： <ul><li>光源数量对计算复杂度影响巨大</li><li>访问深度等数据需要额外的计算</li></ul></li></ul><p><strong>延迟渲染</strong>：</p><ul><li>优点： <ul><li>在有大量光照的场景优势显著</li><li>只渲染可见像素、节省计算量</li><li>对后处理支持良好</li><li>用更少的shader</li></ul></li><li>缺点： <ul><li>不支持半透明物体</li><li>带宽占用大</li><li>对MSAA支持不友好</li></ul></li></ul><h2 id="光照" tabindex="-1">光照 <a class="header-anchor" href="#光照" aria-label="Permalink to &quot;光照&quot;">​</a></h2><h3 id="draw-light-volume-绘制光源形状" tabindex="-1">Draw Light Volume(绘制光源形状) <a class="header-anchor" href="#draw-light-volume-绘制光源形状" aria-label="Permalink to &quot;Draw Light Volume(绘制光源形状)&quot;">​</a></h3><p>Draw Light Volume 的原理是，为每个光源影响范围建成 mesh，并绘制它们。往往是 1 个光源 1 次 draw call，并在 pixel shader 中计算本光源对该 pixel 的光照贡献，并以加法混合的形式叠加到 frame buffer 上。</p><blockquote><p>如下图左为 spot light 的光源形状，下图右为 point light 的光源形状，它们都可以根据光源影响范围、张角等来调整对应光源形状模型的变换。</p></blockquote><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/20240729183113.png" alt="20240729183113"> 缺点：</p><ol><li>过多的 draw call： n 个光源至少要 n 次 draw call，甚至有些方法是需要 2n 次。</li><li>另一种带宽开销：假设 n 个光源覆盖在同 1 个 pixel，那么计算该 pixel 的光照就需要读 n 次 G-Buffer，而在逐像素遍历光源策略中只需要读 1 次。</li></ol><h3 id="tile-based-light-culling" tabindex="-1">Tile-based Light Culling <a class="header-anchor" href="#tile-based-light-culling" aria-label="Permalink to &quot;Tile-based Light Culling&quot;">​</a></h3><p>Tiled-based Light Culling 将屏幕区分划分为多个 tile ，且每个 tile 拥有⼀个光源列表（包含所有在该 tile 内有影响的光源）。 这样就可以在对某个 fragment 着色时，算出该 fragment 所在的 tile，就能找到 tile 对应的光源列表，并对列表里的光源进行光照贡献计算，而不必对整个场景的所有光源进行光照贡献计算。 <img src="https://raw.githubusercontent.com/xumyuan/image/master/20240729183335.png" alt="20240729183335"> 当相机或者光源的位置和方向发生改变时，所有的tile都需要重新计算。 缺点：</p><ul><li>基于屏幕空间的 tile 划分仍然粗糙，没有考虑到深度值（离摄像机远近的距离）划分。</li></ul><blockquote><p>如下图黑色线段物体，每个 shading point 本应该最多同时受到一个光源的影响，由于 tile 划分没有考虑 z 值，从而使得实际每个 shading point 都有三个光源的着色计算：</p></blockquote><p><img src="https://raw.githubusercontent.com/xumyuan/image/master/20240729183502.png" alt="20240729183502"></p>',19)])])}const g=i(r,[["render",o]]);export{c as __pageData,g as default};
